record.field:
for sol in self:
    if not sol.x_bom_id and sol.product_template_id.bom_ids and sol.product_template_id.route_ids: 
        sol['x_bom_id'] = sol.product_template_id.bom_ids.filtered(lambda b: b.x_is_template)[0].id

existing_copied_boms = {}

for b in env['mrp.bom'].search([('x_sale_order_id', 'in', records.sale_line_id.order_id.ids)]):
    existing_copied_boms[(b.product_tmpl_id.id, b.x_sale_order_id.id, b.x_template_id.id)] = b.id

for mo in records:
    if (bom := mo.sale_line_id.x_bom_id):
        so = mo.sale_line_id.order_id

        # case A: this SOL was already duplicated in a previous batch
        if bom.x_sale_order_id.id == so.id:
            custom_bom = bom.id

        # case B: it's a template BOM. Check our cache or create a new one.
        else:
            if (cache_key := (bom.product_tmpl_id.id, so.id, bom.id)) not in existing_copied_boms:
                expected_code = f"{so.name} - {so.partner_id.name}" + f" - {bom.code}" * bool(bom.code)
                existing_copied_boms[cache_key] = bom.copy({'code': expected_code, 'x_sale_order_id': so.id, 'x_template_id': bom.id}).id

            custom_bom = existing_copied_boms[cache_key]
            mo.sale_line_id['x_bom_id'] = custom_bom

        mo.write({'bom_id': custom_bom, 'location_src_id': so.partner_shipping_id.x_ws_location_id.id})
        mo.action_confirm()
